$outputPath = "C:\Resume_App_app\Resume_App_app\testcases_resume_builder_500.xlsx"

$excel = New-Object -ComObject Excel.Application
$excel.Visible = $false
$excel.DisplayAlerts = $false

$workbook = $excel.Workbooks.Add()
$sheet = $workbook.Worksheets.Item(1)
$sheet.Name = "Test Cases"

# --- Headers ---
$headers = @("Test Case ID","Test Type","Feature/Section","Test Scenario","Test Steps","Test Data","Expected Result","Pass/Fail/Negative/Positive")
for ($c = 1; $c -le $headers.Count; $c++) {
    $sheet.Cells.Item(1, $c) = $headers[$c-1]
    $sheet.Cells.Item(1, $c).Font.Bold = $true
    $sheet.Cells.Item(1, $c).Interior.ColorIndex = 37
    $sheet.Cells.Item(1, $c).Font.Color = [System.Drawing.ColorTranslator]::ToOle([System.Drawing.Color]::White)
}

