$row = 2
foreach ($r in $rows) {
    for ($c = 1; $c -le $r.Count; $c++) {
        $sheet.Cells.Item($row, $c) = $r[$c-1]
    }
    # Color Positive rows light green, Negative rows light red
    if ($r[$r.Count-1] -eq "Positive") {
        $sheet.Rows.Item($row).Interior.ColorIndex = 35   # light green
    } else {
        $sheet.Rows.Item($row).Interior.ColorIndex = 22   # light pink/red
    }
    $row++
}

# Auto-fit columns
$usedRange = $sheet.UsedRange
$usedRange.EntireColumn.AutoFit() | Out-Null

# Add AutoFilter so user can filter by Type, Section, Positive/Negative, etc.
$sheet.Rows.Item(1).AutoFilter() | Out-Null

# Freeze header row
$excel.ActiveWindow.SplitRow = 1
$excel.ActiveWindow.FreezePanes = $true

# Save as true xlsx
$workbook.SaveAs($outputPath, 51)   # 51 = xlOpenXMLWorkbook (.xlsx)
$workbook.Close($false)
$excel.Quit()

[System.Runtime.Interopservices.Marshal]::ReleaseComObject($excel) | Out-Null

Write-Host "Done! File saved to: $outputPath"
